css:
body {
    font-family: Arial;
}
.table{
    margin:0px !important;
}
.print-format td, .print-format th {
    padding: 3px !important;
}
.table-bordered tbody{
    border-color: #333c44 !important;
}

@page {
  size: A4;
  margin: 15mm;

  @bottom-center {
    content: "Page " counter(page) " of " counter(pages);
    font-size: 10px;
    color: #555;
  }
}

.footer {
  position: running(footer);
}
